{"code": "import json

# Load HRTX data from file (it's large)
hrtx_file = locals()['var_functions.query_db:58']
with open(hrtx_file, 'r') as f:
    hrtx_data = json.load(f)

# Load BHAT data directly (it's not a file)
bhat_data = locals()['var_functions.query_db:60']

# Calculate volatile days for HRTX
hrtx_volatile = 0
for day in hrtx_data:
    high = float(day['High'])
    low = float(day['Low'])
    if low > 0 and (high - low) / low > 0.20:
        hrtx_volatile += 1

# Calculate volatile days for BHAT
bhat_volatile = 0
for day in bhat_data:
    high = float(day['High'])
    low = float(day['Low'])
    if low > 0 and (high - low) / low > 0.20:
        bhat_volatile += 1

print('__RESULT__:')
print(json.dumps({
    'HRTX': {'symbol': 'HRTX', 'company': 'Heron Therapeutics Inc.', 'volatile_days': hrtx_volatile, 'total_days': len(hrtx_data)},
    'BHAT': {'symbol': 'BHAT', 'company': 'Blue Hat Interactive Entertainment Technology', 'volatile_days': bhat_volatile, 'total_days': len(bhat_data)}
}))"}
